-- ============================================================
-- ANN Top-N Search Regression Test
--
-- 验证 Doris ANN Top-N 搜索的正确性，覆盖：
--   1. 基础 Top-N (l2_distance_approximate + ORDER BY + LIMIT)
--   2. Prepared Statement 方式 (CAST(%s AS ARRAY<FLOAT>))
--   3. 带 Pre-filter 的 Top-N (WHERE + ORDER BY + LIMIT)
--   4. Range Search (WHERE distance < threshold)
--   5. ANN vs 暴力搜索结果对比
--   6. 不同 LIMIT 值
--   7. 不同距离函数 (l2_distance / cosine_distance)
--
-- 前置条件：需要 video_frame_vectors 表已存在且有数据和 ANN 索引
-- ============================================================


-- ============================================================
-- 设置会话变量
-- ============================================================
SET enable_common_expr_pushdown = true;


-- ============================================================
-- T1: 基础 ANN Top-N 搜索
-- 使用 array_repeat 构造常量查询向量
-- ============================================================
SELECT video_id, frame_id,
       l2_distance_approximate(embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) AS score
FROM video_frame_vectors
ORDER BY score ASC
LIMIT 10;


-- ============================================================
-- T2: ANN Top-N — 不同 LIMIT 值
-- ============================================================
SELECT video_id, frame_id,
       l2_distance_approximate(embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) AS score
FROM video_frame_vectors
ORDER BY score ASC
LIMIT 1;

SELECT video_id, frame_id,
       l2_distance_approximate(embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) AS score
FROM video_frame_vectors
ORDER BY score ASC
LIMIT 50;


-- ============================================================
-- T3: 暴力 Top-N (l2_distance, 不走索引)
-- 用于与 T1 对比，验证 ANN 召回质量
-- ============================================================
SELECT video_id, frame_id,
       l2_distance(embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) AS score
FROM video_frame_vectors
ORDER BY score ASC
LIMIT 10;


-- ============================================================
-- T4: 带 Pre-filter 的 ANN Top-N
-- 先按 video_id 过滤，再做向量搜索
-- ============================================================
SELECT video_id, frame_id,
       l2_distance_approximate(embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) AS score
FROM video_frame_vectors
WHERE video_id = 'video_0001'
ORDER BY score ASC
LIMIT 10;


-- ============================================================
-- T5: Range Search — ANN 索引
-- ============================================================
SELECT video_id, frame_id,
       l2_distance_approximate(embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) AS score
FROM video_frame_vectors
WHERE l2_distance_approximate(embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) < 500.0
ORDER BY score ASC
LIMIT 20;


-- ============================================================
-- T6: Range Search — 暴力扫描 (对比)
-- ============================================================
SELECT video_id, frame_id,
       l2_distance(embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) AS score
FROM video_frame_vectors
WHERE l2_distance(embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) < 500.0
ORDER BY score ASC
LIMIT 20;


-- ============================================================
-- T7: 多条件 Pre-filter + ANN Top-N
-- ============================================================
SELECT video_id, frame_id,
       l2_distance_approximate(embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) AS score
FROM video_frame_vectors
WHERE video_id IN ('video_0001', 'video_0002', 'video_0003')
ORDER BY score ASC
LIMIT 10;


-- ============================================================
-- T8: 子查询中使用 ANN Top-N
-- ============================================================
SELECT * FROM (
    SELECT video_id, frame_id,
           l2_distance_approximate(embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) AS score
    FROM video_frame_vectors
    ORDER BY score ASC
    LIMIT 20
) t
WHERE t.score < 600.0
ORDER BY t.score ASC;


-- ============================================================
-- T9: ANN Top-N + JOIN (向量搜索结合元信息)
-- ============================================================
SELECT v.video_id, v.frame_id,
       l2_distance_approximate(v.embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) AS score,
       m.video_source, m.video_type
FROM video_frame_vectors v
INNER JOIN video_meta m ON v.video_id = m.video_id
ORDER BY l2_distance_approximate(v.embedding, array_repeat(CAST(0.01 AS FLOAT), 768)) ASC
LIMIT 10;


